export const Home = () => {

    useEffect = () => {
        try {
            fetch('http://localhost:3000/my-blogs')
            .then(blogData => {
                blogData.json()
                .then((jsonBlog) => {
                    console.log(jsonBlog);
                })
            })
        }
        catch (ex) {
            console.log("Error retrieving blog: ", ex);
        }

    }

